// Normalize incoming job records to a stable schema
const out = [];
for (const item of $input.all()) {
  const j = item.json;
  out.push({ json: {
    jobId: String(j.jobId ?? j.id ?? '').trim(),
    type: typeof j.type === 'string' ? j.type.trim() : j.type ?? null,
    source: j.source ?? 'api',
    receivedAt: new Date().toISOString(),
  } });
}
return out;

// Advance the incremental watermark to the newest record seen
const items = $input.all().map(i => i.json);
const newest = items.reduce((m, j) => {
  const ts = new Date(j.updatedAt || j.receivedAt || 0).getTime();
  return ts > m ? ts : m;
}, 0);
return [{ json: { watermark: new Date(newest || Date.now()).toISOString(), processed: items.length } }];

